#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <omp.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T>
T mask_const[MAX_MASK_WIDTH];

template<typename T>
void conv1d(const T * __restrict__ in,
            T * __restrict__ out,
            const int input_width,
            const int mask_width,
            const int block_size,
            const int num_blocks)
{
  #pragma omp target device(omp_get_default_device())
  {
    #pragma omp teams num_teams(num_blocks)
    {
      #pragma omp distribute parallel for
      for (int i = 0; i < input_width; i++) {
        T s = 0;
        int start = i - mask_width / 2;
        for (int j = 0; j < mask_width; j++) {
          if (start + j >= 0 && start + j < input_width) {
            s += in[start + j] * mask_const<T>[j];
          }
        }
        out[i] = s;
      }
    }
  }
}

template<typename T>
void conv1d_tiled(const T *__restrict__ in,
                  T *__restrict__ out,
                  const int input_width,
                  const int mask_width,
                  const int block_size,
                  const int num_blocks)
{
  int n = mask_width / 2;

  #pragma omp target device(omp_get_default_device())
  {
    #pragma omp teams num_teams(num_blocks)
    {
      #pragma omp distribute parallel for
      for (int i = 0; i < input_width; i++) {
        int block_idx = i / block_size;
        int tid = i % block_size;

        T tile_local[MAX_BLOCK_SIZE + 2 * MAX_MASK_WIDTH]; 

        int base_idx = block_idx * block_size;

        // Load left halo
        int halo_left_idx = (block_idx - 1) * block_size + tid;
        if (tid >= block_size - n) {
          int local_idx = tid - (block_size - n);
          tile_local[local_idx] = (halo_left_idx < 0) ? 0 : in[halo_left_idx];
        }

        // Load current block
        if (i < input_width) {
          tile_local[n + tid] = in[i];
        } else {
          tile_local[n + tid] = 0;
        }

        // Load right halo
        int halo_right_idx = (block_idx + 1) * block_size + tid;
        if (tid < n) {
          int local_idx = tid + block_size + n;
          tile_local[local_idx] = (halo_right_idx >= input_width) ? 0 : in[halo_right_idx];
        }

        #pragma omp barrier

        T s = 0;
        for (int j = 0; j < mask_width; j++) {
          s += tile_local[tid + j] * mask_const<T>[j];
        }

        if (i < input_width) {
          out[i] = s;
        }
      }
    }
  }
}

template<typename T>
void conv1d_tiled_caching(const T *__restrict__ in,
                          T *__restrict__ out,
                          const int input_width,
                          const int mask_width,
                          const int block_size,
                          const int num_blocks)
{
  #pragma omp target device(omp_get_default_device())
  {
    #pragma omp teams num_teams(num_blocks)
    {
      #pragma omp distribute parallel for
      for (int i = 0; i < input_width; i++) {
        int block_idx = i / block_size;
        int tid = i % block_size;

        T tile_local[MAX_BLOCK_SIZE];
        tile_local[tid] = in[i];

        #pragma omp barrier

        int this_tile_start = block_idx * block_size;
        int next_tile_start = (block_idx + 1) * block_size;
        int start = i - (mask_width / 2);
        T s = 0;

        for (int j = 0; j < mask_width; j++) {
          int in_index = start + j;
          if (in_index >= 0 && in_index < input_width) {
            if (in_index >= this_tile_start && in_index < next_tile_start) {
              s += tile_local[tid + j - (mask_width / 2)] * mask_const<T>[j];
            } else {
              s += in[in_index] * mask_const<T>[j];
            }
          }
        }
        out[i] = s;
      }
    }
  }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs(s - d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = input_width * sizeof(T);

  T *a, *b;
  a = (T *)malloc(size_bytes); 
  b = (T *)malloc(size_bytes); 

  T h_mask[MAX_MASK_WIDTH];
  for (int i = 0; i < MAX_MASK_WIDTH; i++) h_mask[i] = 1; 

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = rand() % 256;
  }

  // Copy mask to global constant simulation
  for (int i = 0; i < mask_width; i++) {
    mask_const<T>[i] = h_mask[i];
  }

  // Allocate device memory using OpenMP target data
  T *d_a, *d_b;

  int device = omp_get_default_device();
  d_a = (T*)omp_target_alloc(size_bytes, device);
  d_b = (T*)omp_target_alloc(size_bytes, device);

  if (!d_a || !d_b) {
    printf("Device memory allocation failed\n");
    exit(1);
  }

  // Copy data to device
  omp_target_memcpy(d_a, a, size_bytes, 0, 0, device, omp_get_initial_device());

  // Timing and execution
  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    int num_blocks = input_width / bs;
    if (num_blocks * bs < input_width) num_blocks++;

    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d<T>(d_a, d_b, input_width, mask_width, bs, num_blocks);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);

    // Copy back
    omp_target_memcpy(b, d_b, size_bytes, 0, 0, omp_get_initial_device(), device);
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    int num_blocks = input_width / bs;
    if (num_blocks * bs < input_width) num_blocks++;

    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled<T>(d_a, d_b, input_width, mask_width, bs, num_blocks);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);

    omp_target_memcpy(b, d_b, size_bytes, 0, 0, omp_get_initial_device(), device);
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    int num_blocks = input_width / bs;
    if (num_blocks * bs < input_width) num_blocks++;

    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled_caching<T>(d_a, d_b, input_width, mask_width, bs, num_blocks);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);

    omp_target_memcpy(b, d_b, size_bytes, 0, 0, omp_get_initial_device(), device);
    reference(a, b, h_mask, input_width, mask_width);
  }

  free(a);
  free(b);
  omp_target_free(d_a, device);
  omp_target_free(d_b, device);
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);
  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width); 

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}
